#!/usr/bin/env python
"""Emit a booktabs LaTeX baseline table from the committed baseline_table.json.

Mirrors the paper-a/paper-b convention of \\input-ing generated tables instead of hand-copying
numbers. Usage: python emit_baseline_tex.py baseline_table.json out.tex
"""
import json
import sys


def fmt(x, nd=3):
    try:
        return f"{float(x):.{nd}f}"
    except (TypeError, ValueError):
        return "--"


def main() -> int:
    bt = json.load(open(sys.argv[1]))
    out = sys.argv[2]
    lines = [
        "% GENERATED by tools/emit_baseline_tex.py from out_eval/baseline_table.json -- do not edit.",
        "\\begin{table}[H]", "\\centering", "\\small",
        "\\caption{Baseline zero-shot instruction guards on the frozen benchmark "
        "(\\texttt{public\\_test}, 146 rows: 75 G0/D1, 6 G1, 3 protected pairs). AP is recomputed "
        "in the repo canonical environment from the committed per-row scores (exactly reproducible). "
        "Threshold-free AP$\\cdot$D is moderate (0.67--0.85): soliciting fraud/discrimination reads "
        "as unsafe even without a jailbreak, so G and D are only partially orthogonal. "
        "$\\Delta_{\\mathrm{context}}$ is the mean absolute protected-pair score gap (lower is more "
        "invariant). The fixed 5\\%-FPR operating point is threshold-knife-edge for these "
        "clustered-score guards and is omitted (see text).}",
        "\\label{tab:baseline}",
        "\\begin{tabular}{lrrrr}", "\\toprule",
        "Guard & AP$\\cdot$G & AP$\\cdot$D & AP$\\cdot$final & $\\Delta_{\\mathrm{context}}$ \\\\",
        "\\midrule",
    ]
    for r in bt.get("table", []):
        name = r["guard"].replace("_", "\\_")
        lines.append(f"{name} & {fmt(r.get('AP_G'))} & {fmt(r.get('AP_D'))} & "
                     f"{fmt(r.get('AP_final'))} & {fmt(r.get('delta_context'))} \\\\")
    lines += ["\\bottomrule", "\\end{tabular}"]
    if bt.get("skipped"):
        names = ", ".join(s["guard"].replace("_", "\\_") for s in bt["skipped"])
        lines.append(f"\\\\[2pt]{{\\footnotesize Not scored (gated, HF license not accepted): {names}.}}")
    lines.append("\\end{table}")
    open(out, "w").write("\n".join(lines) + "\n")
    print(f"wrote {out}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
